"""
MKT Original Language Commentary — Galatians chapters 1–3
Run: python3 scripts/zc-original-galatians-1-3.py

Source data used:
- data/interlinear/galatians.json (Strongs tokens)
- data/translation/glossary-greek.json (semantic ranges, dispute levels)
- data/translation/notes/galatians.json (per-verse token detail)
- data/translation/draft/mediating/galatians.json (MKT text)
- data/commentary/ellicott/galatians.json (primary philological source)
- data/commentary/jfb/galatians.json (historical background)

Key decisions in this range:
- πίστεως Ἰησοῦ Χριστοῦ (2:16): the genitive is debated; both objective ("faith in Christ")
  and subjective ("faithfulness of Christ") readings are presented; MKT follows objective
  as primary while acknowledging the subjective reading has contextual support in 3:10-14.
- ἔργων νόμου ("works of the law"): treated as Jewish boundary-marking practices
  (circumcision, food laws, Sabbath), not general moral effort — following the NPP
  linguistic argument; the commentary notes this distinction where it is exegetically decisive.
- δικαιόω: "justify / pronounce righteous" — forensic sense throughout Galatians; the
  commentary treats the term consistently as a legal verdict rather than a moral transformation.
- paidagōgos (3:24): specifically the slave who ESCORTED a minor to school (not the teacher),
  whose function ended when the child reached majority — this distinction is critical for
  Paul's argument that the law's role was temporary and custodial, not permanently instructive.
- The Antioch incident (2:11-14): treated as a historical event prior to the Jerusalem
  council of Acts 15, probably at the interval described in Acts 15:35.
- Terminology: "Paul" throughout (not "the Apostle"); "the agitators" or "the intruders"
  for the Judaizing opponents; "the pillar apostles" for James, Cephas, and John (following
  Paul's own ironic label in 2:9).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GALATIANS = {
  "1": {
    "1": '<p><strong>ἀπόστολος</strong> — "apostle" — taken in its strictest sense here; Paul is insisting on equality with the Twelve, not merely on a lesser missionary function. <strong>οὐκ ἀπ᾽ ἀνθρώπων οὐδὲ δι᾽ ἀνθρώπου</strong> (<em>ouk ap\' anthrōpōn oude di\' anthrōpou</em>) — the double negative covers both the origin (<em>apo</em>, "from" = source) and the channel (<em>dia</em>, "through" = intermediary): Paul\'s apostolate derives from no human community and was transmitted through no human intermediary. The opening sentence is the most polemically loaded salutation in the NT — the argument of the entire letter is compressed into the first clause.</p><p><strong>ἀλλὰ διὰ Ἰησοῦ Χριστοῦ καὶ θεοῦ πατρός</strong> — "but through Jesus Christ and God the Father" — the coordinate pairing of Christ and the Father as the joint source of apostolic commission is an implicit Christological claim: Christ stands on the divine side of the origin of Paul\'s call.</p>',
    "2": '<p><strong>ταῖς ἐκκλησίαις τῆς Γαλατίας</strong> (<em>tais ekklēsiais tēs Galatias</em>) — "to the churches of Galatia." <em>Ekklēsia</em> (assembly, church) is the Greek civic term for the assembly of citizens called together for public deliberation, applied to the gathered community of believers. The plural "churches" indicates multiple congregations across the Galatian region, all receiving the same letter — an unusual circular format suggesting the issue being addressed was not local but regional, a coordinated effort by the agitators across multiple communities.</p>',
    "3": '<p><strong>χάρις ὑμῖν καὶ εἰρήνη</strong> — "grace to you and peace" — the standard Pauline greeting fuses the Greek epistolary opener (<em>chairein</em> = greetings, reshaped to <em>charis</em> = grace) with the Hebrew/Aramaic <em>shalom</em> (peace). The pairing is not merely formulaic: grace and peace name the content of the gospel — unmerited favor from God and its fruit in restored relationship. <strong>ἀπὸ θεοῦ πατρὸς ἡμῶν καὶ κυρίου Ἰησοῦ Χριστοῦ</strong> — both God the Father and the Lord Jesus Christ are presented as the joint origin of these gifts; the preposition <em>apo</em> (from) governs both, placing Christ coordinate with the Father as the source of saving grace.</p>',
    "4": '<p><strong>τοῦ δόντος ἑαυτὸν ὑπὲρ τῶν ἁμαρτιῶν ἡμῶν</strong> (<em>tou dontos heauton hyper tōn hamartiōn hēmōn</em>) — "who gave himself for our sins." The aorist participle <em>dontos</em> (having given) points to the single completed event of the cross; <em>heauton</em> (himself) emphasizes voluntariness — not something done to him but something he surrendered. The giving has a parallel in Titus 2:14 and the ransom-saying of Mark 10:45.</p><p><strong>ὅπως ἐξέληται ἡμᾶς ἐκ τοῦ αἰῶνος τοῦ ἐνεστῶτος πονηροῦ</strong> — "to rescue us from the present evil age." <em>Exaireō</em> (to take out, rescue) has OT exodus resonance — God "taking out" Israel from Egypt. <em>Aiōn ho enestōs ponēros</em> (the present evil age) is the Jewish two-age schema: this age of sin and death is being displaced by the age to come, inaugurated in Christ\'s death and resurrection.</p>',
    "5": '<p><strong>ᾧ ἡ δόξα εἰς τοὺς αἰῶνας τῶν αἰώνων</strong> — "to whom be the glory forever and ever." The doxology at the start of the letter rather than the end is unusual; Paul typically reserves doxologies for conclusions (cf. Rom 11:36; 16:27). Its placement here grounds the entire theological argument that follows in an act of worship: the rescue from the present evil age (v4) is itself the occasion for praise. The definite article <em>hē doxa</em> (the glory) — not merely glory in general but the pre-eminent divine glory proper to God alone.</p>',
    "6": '<p><strong>μετατίθεσθε</strong> (<em>metatithesthe</em>) — "you are deserting." The word is regularly used in Greek for a deserter in war, a political turncoat, or a religious apostate — the most charged available term for switching allegiance. The present tense is significant: the defection is in process, not complete. Paul writes to arrest a movement still underway. <em>Thaumazō</em> (I am astonished) expresses genuine shock, not merely rhetorical emphasis — the speed of the desertion is what stuns Paul: <em>houtōs tacheōs</em> (so quickly).</p><p><strong>ἀπὸ τοῦ καλέσαντος ὑμᾶς ἐν χάριτι Χριστοῦ</strong> — "from the one who called you by the grace of Christ." The object of desertion is not a doctrine but a person — the God who called them. The Galatians\' adoption of the other gospel is not merely theological error but a relational abandonment.</p>',
    "7": '<p><strong>ὃ οὐκ ἔστιν ἄλλο</strong> — "which is not another gospel" — more precisely, "which is not of a different kind." The Greek <em>allo</em> (another of the same kind) vs. <em>heteron</em> (another of a different kind) distinction is technically relevant: Paul has said <em>heteron euangelion</em> in v6 (another-different gospel); here he says it is not <em>allo</em> (not another-same gospel) — it is no gospel at all.</p><p><strong>οἱ ταράσσοντες ὑμᾶς καὶ θέλοντες μεταστρέψαι τὸ εὐαγγέλιον τοῦ Χριστοῦ</strong> — <em>tarassō</em> (to stir up, agitate, disturb) — used for the agitation of water and civic disturbances. <em>Metastrephō</em> (to turn completely around, pervert) — stronger than "change": a radical inversion of the gospel\'s character.</p>',
    "8": '<p><strong>ἀνάθεμα ἔστω</strong> (<em>anathema estō</em>) — "let him be accursed." <em>Anathema</em> (Greek rendering of Hebrew <em>cherem</em>) is the most extreme form of religious exclusion: devoted to destruction, cut off from the covenant community and placed under divine curse. The twice-stated anathema — in vv8 and 9 — frames the warning with the legal weight of double witness (Deut 19:15). The hypothetical extreme — "even if we ourselves or an angel from heaven" — is not rhetorical flourish but the establishment of an absolute: no source of authority whatsoever can legitimate a different gospel.</p><p>The irony is sharp: the agent who preaches another gospel falls under the same curse-structure that the genuine gospel announces as Christ\'s fate on behalf of sinners (3:13: "cursed is everyone who hangs on a tree").</p>',
    "9": '<p><strong>ὡς προειρήκαμεν</strong> (<em>hōs proeirēkamen</em>) — "as we said before." The "before" probably refers to Paul\'s previous visit — already at that stage the threat was visible and he had warned against it. The repetition now in writing doubles the witness: two formal statements, satisfying the Jewish-legal requirement of two witnesses to establish a matter (Deut 19:15). The anathema on the other-gospel-preacher is not personal anger but a legal verdict rendered twice for its binding force.</p>',
    "10": '<p><strong>ἀνθρώπους πείθω ἢ τὸν θεόν</strong> (<em>anthrōpous peithō ē ton theon</em>) — "am I now seeking to please people, or God?" <em>Peithō</em> (to persuade, win approval, conciliate) targets the charge that Paul\'s law-free gospel was a people-pleasing accommodation to Gentile sensibilities — a softening of full Jewish covenant requirements to attract converts. The rhetorical question is anticipatory: the autobiography of vv11-24 will prove that his gospel came at enormous personal cost, not as a strategy for winning human favor. <strong>εἰ ἔτι ἀνθρώποις ἤρεσκον, Χριστοῦ δοῦλος οὐκ ἂν ἤμην</strong> — "if I were still trying to please people, I would not be a servant of Christ" — the present-unreal conditional establishes that the two postures are mutually exclusive.</p>',
    "11": '<p><strong>τὸ εὐαγγέλιον τὸ εὐαγγελισθὲν ὑπ᾽ ἐμοῦ ὅτι οὐκ ἔστιν κατὰ ἄνθρωπον</strong> (<em>kata anthrōpon</em>) — "not of human origin" — literally "not according to the human standard or norm." Paul denies that his gospel fits the pattern of humanly-derived teaching, philosophical tradition, or institutional transmission. The passive <em>euangelisthen</em> (was proclaimed) hints at divine agency: the gospel was proclaimed through Paul but did not originate with him.</p>',
    "12": '<p><strong>ἀλλὰ δι᾽ ἀποκαλύψεως Ἰησοῦ Χριστοῦ</strong> (<em>apokalypseōs Iēsou Christou</em>) — "through a revelation of Jesus Christ." The genitive is likely both objective and subjective simultaneously: a revelation about Jesus Christ (its content) and a revelation from / given by Jesus Christ (its source). The Damascus encounter was simultaneously a disclosure of who Christ is and an act of divine self-disclosure by Christ himself. <em>Apokalypsis</em> (revelation, uncovering) contrasts with gradual human discovery: this was a sudden, unconditional divine disclosure that overturned Paul\'s entire prior framework.</p>',
    "13": '<p><strong>τὴν ἐμὴν ἀναστροφήν ποτε ἐν τῷ Ἰουδαϊσμῷ</strong> (<em>anastrophē</em>) — "my former way of life in Judaism." <em>Anastrophē</em> (conduct, way of life, pattern of behavior) covers the entire complex of values, practices, and allegiances that constituted Paul\'s pre-conversion identity — not merely religious practice but who he was. <em>Ioudaismos</em> (Judaism) — a term Paul uses only here and v14 in the NT; it appears in 2 Maccabees for the distinctively Jewish way of life in opposition to Hellenistic assimilation. Paul does not disparage Judaism but describes his life as conducted within and for its advance.</p>',
    "14": '<p><strong>προέκοπτον ἐν τῷ Ἰουδαϊσμῷ ὑπὲρ πολλοὺς συνηλικιώτας</strong> (<em>proekopton</em>) — "I was advancing in Judaism beyond many of my own age." <em>Prokoptō</em> (to advance, cut a path forward, make progress) is an ambitious term implying swift movement toward a defined goal: Paul was not a passive participant but a high-achiever pressing past his contemporaries.</p><p><strong>ζηλωτὴς ὑπάρχων τῶν πατρικῶν μου παραδόσεων</strong> — "extremely zealous for the traditions of my fathers." <em>Zēlōtēs</em> (zealot, one burning with zeal) connects Paul to the Phinehas-tradition (Num 25:11-13) of violent zeal for Torah-purity — the same zeal that drove his persecution of the church. The traditions of the fathers (<em>patrikōn paradoseon</em>) are the oral Torah, the interpretive framework built around the written law.</p>',
    "15": '<p><strong>ὁ ἀφορίσας με ἐκ κοιλίας μητρός μου</strong> (<em>ho aphorisas me ek koilias mētros mou</em>) — "the one who set me apart from my mother\'s womb." <em>Aphorizō</em> (to set apart, separate, mark off) — the same root as <em>Pharisaios</em> (Pharisee = the separated one) and Paul\'s self-description in Rom 1:1 (<em>aphorismenon eis euangelion</em> = set apart for the gospel). The irony is profound: the Pharisee defined by separation from the impure discovers that God\'s prior act of separation was for the opposite purpose — to bring the gospel to the Gentiles, the very group from whom Pharisees separated. The prophetic echoes are deliberate: Jeremiah 1:5 ("before you were born I set you apart") and the Servant of Isa 49:1 ("before I was born the LORD called me") both shape Paul\'s self-understanding of a prenatal divine commission.</p>',
    "16": '<p><strong>ἀποκαλύψαι τὸν υἱὸν αὐτοῦ ἐν ἐμοί</strong> (<em>en emoi</em>) — "to reveal his Son in me." The phrase is remarkable: not <em>moi</em> (to me, external vision) but <em>en emoi</em> (in me, interior transformation). The revelation was not merely visual data from outside but a life-reorienting disclosure within Paul\'s own being. This interior Christ is the theological ground of Paul\'s gospel: what he proclaims he received not as information passed on from others but as a living reality disclosed within him.</p><p><strong>ἵνα εὐαγγελίζωμαι αὐτὸν ἐν τοῖς ἔθνεσιν</strong> — the purpose clause connects the interior revelation to the exterior mission: the in-me disclosure of the Son was given for the sake of the out-to-the-nations proclamation. The two <em>en</em> phrases (in me / among the Gentiles) frame the missionary paradox.</p>',
    "17": '<p><strong>οὐδὲ ἀνῆλθον εἰς Ἱεροσόλυμα πρὸς τοὺς πρὸ ἐμοῦ ἀποστόλους</strong> — "I did not go up to Jerusalem to those who were apostles before me." The deliberate non-consultation is Paul\'s primary biographical evidence: he had the opportunity to receive the gospel from the Jerusalem apostles and declined it. Going "up to Jerusalem" (always the verb for travel to that elevated city) was the natural move for any new convert seeking authorization; Paul instead went to Arabia and Damascus. The independence is geographic as well as theological.</p>',
    "18": '<p><strong>ἀνῆλθον εἰς Ἱεροσόλυμα ἱστορῆσαι Κηφᾶν</strong> (<em>historesai Kēphan</em>) — "I went up to Jerusalem to visit Cephas." <em>Historeō</em> (to inquire of, visit for information, get acquainted with) — the term implies purposeful personal acquaintance rather than official consultation. Paul went to get to know Peter (Cephas), not to receive instruction from him or obtain apostolic authorization. The fifteen-day stay was social and informational; the brevity itself argues against an apprenticeship reading.</p>',
    "19": '<p><strong>ἕτερον δὲ τῶν ἀποστόλων οὐκ εἶδον, εἰ μὴ Ἰάκωβον τὸν ἀδελφὸν τοῦ κυρίου</strong> — "I saw none of the other apostles — only James the Lord\'s brother." The identification <em>ton adelphon tou kyriou</em> (the Lord\'s brother) uses the standard Greek term <em>adelphos</em> (sibling), the same word used throughout the NT for Jesus\'s brothers (Mark 3:31; 6:3; John 7:3). Whether this means biological brother, half-brother, or cousin has been debated since the patristic period; the phrase leaves the Greek ambiguous but the most natural reading of <em>adelphos</em> without qualification is a full brother.</p>',
    "20": '<p><strong>ἰδοὺ ἐνώπιον τοῦ θεοῦ ὅτι οὐ ψεύδομαι</strong> — "before God I assure you that what I am writing is no lie." The divine witness invocation — "before God" — is the functional equivalent of a formal oath. Its presence here signals the severity of the accusations being answered: Paul\'s opponents were claiming his gospel was dependent on Jerusalem and was therefore a deviant simplification when stripped of circumcision and food laws. The solemn attestation establishes his autobiographical account as legally binding testimony, not rhetorical self-defense.</p>',
    "21": '<p><strong>εἰς τὰ κλίματα τῆς Συρίας καὶ τῆς Κιλικίας</strong> (<em>klimata</em>) — "the regions of Syria and Cilicia." <em>Klimata</em> (zones, sectors, geographical areas) suggests a broad regional itinerary rather than specific city visits. Cilicia includes Tarsus, Paul\'s hometown; Syria includes Antioch, which became his primary missionary base. The spatial independence reinforces the theological argument: Paul operated in regions geographically distant from Jerusalem\'s immediate sphere.</p>',
    "22": '<p><strong>ἤμην δὲ ἀγνοούμενος τῷ προσώπῳ ταῖς ἐκκλησίαις τῆς Ἰουδαίας</strong> — "I was personally unknown to the churches of Judea." <em>Tō prosōpō</em> (by face, in person) specifies that the anonymity was physical: the Judean churches did not know his face. The imperfect <em>ēmyn agnoumenos</em> (I continued unknown) implies ongoing anonymity across the period. This seals the independence argument: not only did Paul not receive his gospel from the Jerusalem apostles, the very communities that would have transmitted Jerusalem tradition did not know him by sight.</p>',
    "23": '<p><strong>ὁ διώκων ἡμᾶς ποτε νῦν εὐαγγελίζεται τὴν πίστιν ἥν ποτε ἐπόρθει</strong> — "the one who formerly persecuted us is now proclaiming the faith he once tried to destroy." The verbal chiasm — <em>diōkōn</em> (persecuting) and <em>eporthei</em> (destroying) reversed by <em>euangelizetai</em> (now proclaiming) — structures the conversion as a radical inversion. <em>Portheō</em> (to devastate, ravage, destroy) is Paul\'s own word for his pre-conversion activity (v13); the Judean churches now use it in their report about him. The reversal is so complete that it becomes itself the occasion for praise.</p>',
    "24": '<p><strong>καὶ ἐδόξαζον ἐν ἐμοὶ τὸν θεόν</strong> (<em>edoxazon en emoi ton theon</em>) — "and they glorified God because of me." The imperfect <em>edoxazon</em> (they kept on glorifying) describes ongoing, continuous praise. <em>En emoi</em> (in me, because of me) — the same construction as 1:16 ("to reveal his Son in me"): the same interior-in-me that was the location of God\'s revealing act is now the occasion of God\'s glorification among the Judean believers. The transformed persecutor is not merely a biographical curiosity; his existence as a living gospel-proclaimer is an ongoing act of worship rising from the Jewish church.</p>'
  },
  "2": {
    "1": '<p><strong>διὰ δεκατεσσάρων ἐτῶν</strong> (<em>dia dekatessarōn etōn</em>) — "after fourteen years." Whether reckoned from Paul\'s conversion or from the previous Jerusalem visit (1:18) is one of the most discussed chronological puzzles in Pauline scholarship, with significant implications for the dating of Galatians and the relationship to Acts 15. <strong>κατὰ ἀποκάλυψιν</strong> (<em>kata apokalypsin</em>) — "according to revelation" — the divine-revelation language of 1:12 reappears: even this deliberate consultation was prompted by a direct divine revelation, not human pressure or hierarchy. The consultation is not a concession to Jerusalem authority but a revelation-guided coordination.</p>',
    "2": '<p><strong>ἀνεθέμην αὐτοῖς τὸ εὐαγγέλιον ὃ κηρύσσω ἐν τοῖς ἔθνεσιν</strong> (<em>anethemēn</em>) — "I presented to them the gospel I proclaim among the Gentiles." <em>Anatithēmi</em> (to lay before, present for consideration) implies a collegial consultation, not a submission for approval: Paul laid out his gospel for mutual examination and understanding, not to receive authorization or endorsement of its content.</p><p><strong>μή πως εἰς κενὸν τρέχω ἢ ἔδραμον</strong> — "lest somehow I was running or had run in vain." The athletic metaphor of running (<em>trechō/trechein</em>) in vain signals the practical concern: not that his gospel might be wrong, but that the two missions (circumcised and uncircumcised) might be working at cross-purposes in a way that would neutralize both.</p>',
    "3": '<p><strong>οὐδὲ Τίτος ὁ σὺν ἐμοί, Ἕλλην ὤν, ἠναγκάσθη περιτμηθῆναι</strong> — "but even Titus, who was with me, was not compelled to be circumcised, even though he was a Greek." Titus is the test case: an uncircumcised Gentile believer physically present at the Jerusalem consultation, and not required to undergo circumcision. The aorist passive <em>ēnankasthē</em> (was not compelled) is the operative word — not that no one raised the issue, but that no compulsion was exerted. The pillar apostles\' implicit approval of Titus\'s status is Paul\'s evidence that the Jerusalem leadership did not require circumcision as a condition of the Gentile mission.</p>',
    "4": '<p><strong>διὰ δὲ τοὺς παρεισάκτους ψευδαδέλφους</strong> (<em>pareisaktous pseudadelphous</em>) — "because of the false brothers secretly brought in." <em>Pareisagō</em> (to bring in stealthily alongside) has the prefix <em>para-eis-</em> indicating infiltration: these individuals entered the gathering without proper standing. <em>Pseudadelphos</em> (false brother) is Paul\'s sharpest label — their claim of brotherhood is negated by their agenda. <strong>οἵτινες παρεισῆλθον κατασκοπῆσαι τὴν ἐλευθερίαν ἡμῶν</strong> — <em>kataskopeo</em> (to spy out, reconnoiter) is a military intelligence term; the intruders were scouts assessing the situation before a campaign to bring the Gentile mission under circumcision-requirement.</p>',
    "5": '<p><strong>οἷς οὐδὲ πρὸς ὥραν εἴξαμεν τῇ ὑποταγῇ</strong> — "to whom we did not yield submission even for an hour." <em>Eikaō</em> (to yield, give way, capitulate) — the deliberate non-yielding: even temporary compliance would have been a concession in principle. "Not for an hour" is idiomatic emphasis: no partial accommodation, no provisional compliance pending clarification. The theological stake, stated in the purpose clause, is absolute: <strong>ἵνα ἡ ἀλήθεια τοῦ εὐαγγελίου διαμείνῃ πρὸς ὑμᾶς</strong> — "so that the truth of the gospel might remain with you" — the Galatians\' own access to the gospel was at stake in Paul\'s resistance.</p>',
    "6": '<p><strong>οἱ δοκοῦντες εἶναί τι</strong> (<em>hoi dokountes einai ti</em>) — "those who were considered to be something." The construction <em>hoi dokountes</em> (the reputed ones, those considered to be) is mildly ironic without being dismissive: Paul acknowledges the pillar apostles\' reputation while refusing to let reputation function as theological authority. <strong>πρόσωπον θεὸς ἀνθρώπου οὐ λαμβάνει</strong> — "God shows no favoritism" — literally "God does not take the face of a person" (<em>prosōpon... lambanō</em>). This is the LXX idiom for partiality, translating Hebrew <em>nasa panim</em> (lift the face = show special favor). God\'s impartiality is the principle that subordinates reputation to truth.</p>',
    "7": '<p><strong>πεπίστευμαι τὸ εὐαγγέλιον τῆς ἀκροβυστίας</strong> (<em>pepisteumai</em>) — "I have been entrusted with the gospel for the uncircumcised." The perfect passive <em>pepisteumai</em> (I have been entrusted and remain entrusted) marks the divine commissioning as completed and ongoing. The contrasting genitives — <em>tēs akrobystias</em> (of the uncircumcision) and <em>tēs peritomēs</em> (of the circumcision) — identify the target audiences, not two different gospels: the same gospel to two distinct mission fields.</p>',
    "8": '<p><strong>ὁ γὰρ ἐνεργήσας Πέτρῳ εἰς ἀποστολὴν τῆς περιτομῆς ἐνήργησεν καὶ ἐμοί</strong> (<em>energeō</em>) — "the one who worked effectively in Peter for his apostleship to the circumcised worked effectively in me also." <em>Energeō</em> (to operate powerfully, work effectively) — the same verb in both clauses, emphasizing identical divine empowerment: the God who made Peter\'s apostolate effective made Paul\'s effective by the same means. The parallel structure places the two apostolicates in structural equivalence under the same divine agency — no hierarchy, no derivation of one from the other.</p>',
    "9": '<p><strong>Ἰάκωβος καὶ Κηφᾶς καὶ Ἰωάννης, οἱ δοκοῦντες στῦλοι εἶναι</strong> (<em>styloi</em>) — "those reputed to be pillars." <em>Styloi</em> (columns, structural supports) is an architectural metaphor for those who bear the weight of the community: the pillars of the Jerusalem church. The order — James, Cephas, John — may reflect the authority structure of the early Jerusalem community, with James as its de facto president. <strong>δεξιὰς ἔδωκαν ἐμοὶ καὶ Βαρναβᾷ κοινωνίας</strong> — the right hand of fellowship (<em>dexia koinōnias</em>) was the formal gesture of recognized partnership and agreement in the Greco-Roman world: the pillar apostles acknowledged the Pauline mission as genuine and coordinate, not derivative.</p>',
    "10": '<p><strong>μόνον τῶν πτωχῶν ἵνα μνημονεύωμεν</strong> — "only that we remember the poor." The single explicit condition of the Jerusalem agreement: material support for the poor of the Jerusalem community — probably the foundation of the collection that became a major Pauline project (1 Cor 16:1-4; 2 Cor 8-9; Rom 15:25-28). <strong>ὃ καὶ ἐσπούδασα αὐτὸ τοῦτο ποιῆσαι</strong> — "the very thing I was eager to do." <em>Spoudazō</em> (to be diligent, eager, make haste) — Paul embraced this obligation enthusiastically. The collection was not a burden imposed by Jerusalem but a chosen expression of the Gentile church\'s solidarity with the mother church.</p>',
    "11": '<p><strong>κατὰ πρόσωπον αὐτῷ ἀντέστην</strong> (<em>kata prosōpon autō antestēn</em>) — "I opposed him to his face." <em>Kata prosōpon</em> (face to face, publicly) is the opposite of speaking behind someone\'s back; Paul confronted Peter directly and in front of the assembly. The incident probably belongs to the period described in Acts 15:35 — the interval after Paul and Barnabas\'s return to Antioch and before the second missionary journey. <strong>ὅτι κατεγνωσμένος ἦν</strong> — "because he stood condemned." <em>Kataginōskō</em> (to find fault, condemn, bring in a verdict against) in the perfect passive: the verdict against Peter\'s behavior was already rendered before Paul spoke — Paul\'s rebuke made public what was already true by the standard of the gospel.</p>',
    "12": '<p><strong>πρὸ τοῦ γὰρ ἐλθεῖν τινας ἀπὸ Ἰακώβου μετὰ τῶν ἐθνῶν συνήσθιεν</strong> (<em>synēsthien</em>) — "before certain people came from James, he used to eat with the Gentiles." <em>Synesthiō</em> (to eat together with) — the table fellowship Peter maintained with Gentile believers was the practical expression of the equality-in-Christ that the gospel implied; sharing a meal was the strongest social bond available in the ancient world. <strong>ὅτε δὲ ἦλθον, ὑπέστελλεν καὶ ἀφώριζεν ἑαυτόν</strong> — <em>hypostellō</em> (to shrink back, withdraw) and <em>aphorizō</em> (to separate, set apart) — the Pharisaic separation vocabulary reenacted in the church; Peter re-enacted the wall the gospel had dismantled.</p>',
    "13": '<p><strong>καὶ συνυπεκρίθησαν αὐτῷ καὶ οἱ λοιποὶ Ἰουδαῖοι</strong> (<em>synypokrithēsan</em>) — "and the rest of the Jewish believers joined him in his hypocrisy." <em>Synypokrinomai</em> (to act hypocritically alongside, play the same part together) — the theatrical image: actors performing a role that does not match their actual convictions. The compound verb (<em>syn-</em> = together) emphasizes the collective dimension: the hypocrisy was contagious and coordinated. <strong>ὥστε καὶ Βαρναβᾶς συναπήχθη αὐτῶν τῇ ὑποκρίσει</strong> — <em>sunapagō</em> (to lead away together with, be swept off course alongside) — even Paul\'s mission-partner was carried along by the social force of the crowd; the defection was not calculated but social-pressure-driven.</p>',
    "14": '<p><strong>οὐκ ὀρθοποδοῦσιν πρὸς τὴν ἀλήθειαν τοῦ εὐαγγελίου</strong> (<em>orthopodousin</em>) — "they were not walking in line with the truth of the gospel." <em>Orthopodeō</em> (to walk straight, walk with upright feet) — a hapax in Paul, probably coined from <em>orthos</em> (straight) + <em>pous</em> (foot): walking a straight line rather than a crooked one. The standard is not human propriety but "the truth of the gospel" — the gospel\'s own logic is the measure against which Peter\'s withdrawal was found deviant.</p><p><strong>εἰ σύ, Ἰουδαῖος ὑπάρχων, ἐθνικῶς... ζῇς, πῶς τὰ ἔθνη ἀναγκάζεις ἰουδαΐζειν</strong> — the argument from Peter\'s own prior practice: if he himself had been living as a Gentile (without food-law separations), his withdrawal was not theological consistency but social fear. <em>Ioudaizein</em> (to Judaize, live in the Jewish manner) is the crux: Gentile believers were being effectively compelled to adopt Jewish practice as the hidden condition of full fellowship.</p>',
    "15": '<p><strong>ἡμεῖς φύσει Ἰουδαῖοι καὶ οὐκ ἐξ ἐθνῶν ἁμαρτωλοί</strong> (<em>physei Ioudaioi</em>) — "we who are Jews by nature." <em>Physei</em> (by birth, by nature) marks the innate status as opposed to acquired status. "Gentile sinners" (<em>ex ethnōn hamartoōloi</em>) is the stock Jewish description of those outside the covenant — Gentiles were sinners by definition because they lived without Torah. Paul uses the phrase not to endorse its contempt for Gentiles but to work from a premise shared with his Jewish interlocutor: even those who began with Jewish birth-privilege have discovered that justification does not flow from that privilege.</p>',
    "16": '<p><strong>οὐ δικαιοῦται ἄνθρωπος ἐξ ἔργων νόμου ἐὰν μὴ διὰ πίστεως Ἰησοῦ Χριστοῦ</strong> — "a person is not justified by the works of the law but through the faith/faithfulness of Jesus Christ." <em>Pisteos Iēsou Christou</em> — the genitive is debated: "faith in Jesus Christ" (objective genitive: human faith directed toward Christ — the traditional reading) vs. "the faithfulness of Jesus Christ" (subjective genitive: Christ\'s own faithful obedience as the ground of justification). Paul\'s subsequent argument in 3:10-14 — where Christ actively "becomes a curse" on behalf of others — tilts toward the subjective reading as at least a contributing sense; but both are theologically coherent, and neither is to be excluded.</p><p><em>Ergōn nomou</em> (works of the law) — the specific practices that marked Jewish covenant membership and maintained its boundaries (circumcision, food laws, Sabbath, festival observance), not "good works" in the general moral sense. The triple repetition of the phrase in this verse (<em>ex ergōn nomou... ex ergōn nomou... ex ergōn nomou</em>) underscores how central the debate over these boundary practices was to the Galatian crisis.</p>',
    "17": '<p><strong>εἰ δὲ ζητοῦντες δικαιωθῆναι ἐν Χριστῷ εὑρέθημεν καὶ αὐτοὶ ἁμαρτωλοί, ἆρα Χριστὸς ἁμαρτίας διάκονος; μὴ γένοιτο</strong> — "if, in seeking to be justified in Christ, we ourselves also are found to be sinners, is Christ then a servant of sin? By no means!" The argument: if Jewish believers who have abandoned law-keeping for faith in Christ are thereby "sinners" (because they have transgressed the law\'s framework by eating with Gentiles), does Christ — the one who led them to that transgression — become sin\'s servant? <em>Mē genoito</em> (the strongest possible negative: may it never be!) categorically rejects the conclusion.</p>',
    "18": '<p><strong>εἰ γὰρ ἃ κατέλυσα ταῦτα πάλιν οἰκοδομῶ, παραβάτην ἐμαυτὸν συνιστάνω</strong> — "for if I rebuild what I demolished, I prove myself to be a lawbreaker." The logic is pointed: Peter tore down the wall of separation by eating with Gentiles; by withdrawing, he rebuilt it. The rebuilding retroactively declares the original tearing-down to have been a transgression. Peter\'s withdrawal does not protect him from the accusation of lawbreaking — it constitutes a self-condemnation of his previous inclusive practice. The one who goes back establishes the wrongness of going forward.</p>',
    "19": '<p><strong>ἐγὼ γὰρ διὰ νόμου νόμῳ ἀπέθανον ἵνα θεῷ ζήσω</strong> — "for through the law I died to the law so that I might live to God." The prepositions are carefully distinguished: dying <em>dia nomou</em> (through, by means of the law) and dying <em>nomō</em> (to the law, in relation to the law). The law\'s own logic — Deut 27:26\'s comprehensive curse; Lev 18:5\'s unattainable demand — drives the honest observer to recognize that the law cannot produce the righteousness it demands. The law becomes the instrument of its own undoing for Paul: following it to its conclusion arrives at death, and through that death comes freedom from its claim. <strong>Χριστῷ συνεσταύρωμαι</strong> — "I have been crucified with Christ" — perfect passive: a completed co-crucifixion with permanent present effects. The same compound as Rom 6:6; the death with Christ is both past event and present reality of identity.</p>',
    "20": '<p><strong>ζῶ δὲ οὐκέτι ἐγώ, ζῇ δὲ ἐν ἐμοὶ Χριστός</strong> — "it is no longer I who live, but Christ who lives in me." The displacement of the <em>egō</em> by the indwelling Christ is the positive consequence of co-crucifixion: the old self is put to death, but the one living now is not a vacuum but the Christ-inhabited new self. The present tense <em>zō... zē</em> (I live... Christ lives) describes a permanent present state, not a momentary experience.</p><p><strong>ἐν πίστει ζῶ τῇ τοῦ υἱοῦ τοῦ θεοῦ τοῦ ἀγαπήσαντός με καὶ παραδόντος ἑαυτὸν ὑπὲρ ἐμοῦ</strong> — "I live by faith in the Son of God, who loved me and gave himself for me." The most intensely personal confession in Galatians: not "loved us" but "loved me" (<em>agapēsantos me</em>). The universal scope of the atonement is individualized in Paul\'s own experience; what Christ did for the world Paul claims as having been done for him specifically. This is not narcissism but the grammar of faith: the gospel must be received in the first person singular before it can be proclaimed in the first person plural.</p>',
    "21": '<p><strong>οὐκ ἀθετῶ τὴν χάριν τοῦ θεοῦ</strong> (<em>atheteō</em>) — "I do not nullify the grace of God." <em>Atheteō</em> (to set aside, declare void, render inoperative) is a legal term for nullifying a contract or reversing a verdict. To accept circumcision as a condition of justification would be to declare grace unnecessary — to nullify God\'s gift by claiming you do not need it.</p><p><strong>εἰ γὰρ διὰ νόμου δικαιοσύνη, ἄρα Χριστὸς δωρεὰν ἀπέθανεν</strong> — "for if righteousness comes through the law, then Christ died for nothing." <em>Dōrean</em> (freely, without cause, to no purpose) — the same adverb as "hated me without cause" in Ps 69:4 / John 15:25. If law-keeping could produce righteousness, Christ\'s death was not merely unnecessary but gratuitous — an unjustified event in the cosmos. The logic cuts both ways: either Christ\'s death is necessary (because law-keeping cannot justify) or it was a meaningless waste.</p>'
  },
  "3": {
    "1": '<p><strong>Ὦ ἀνόητοι Γαλάται</strong> (<em>anoētoi</em>) — "O foolish Galatians!" <em>Anoētos</em> (not using the mind, lacking understanding) — a censure of intellectual failure rather than moral failure; the Galatians are not wicked but foolish. This word differs from the term used for moral fools in Matthew 7:26 or 1 Cor 1:20; Paul charges not wickedness but failure to think through what they have experienced.</p><p><strong>τίς ὑμᾶς ἐβάσκανεν</strong> — "who has bewitched you?" <em>Baskaino</em> (to bewitch, cast the evil eye, fascinate) — the only NT use of this term; it implies a malevolent external force has distorted their perception. <strong>οἷς κατ᾽ ὀφθαλμοὺς Ἰησοῦς Χριστὸς προεγράφη ἐσταυρωμένος</strong> — "before your very eyes Jesus Christ was publicly portrayed as crucified." <em>Prographō</em> (to write publicly, post, placard) — a public announcement posted for all to see; Paul\'s preaching of the crucified Christ was as vivid and public as a civic proclamation in the agora.</p>',
    "2": '<p><strong>ἐξ ἀκοῆς πίστεως ἢ ἐξ ἔργων νόμου</strong> (<em>akoēs pisteōs</em>) — "from the hearing of faith or from the works of the law?" <em>Akoē pisteōs</em> can be read as (a) "the hearing that consists in faith" (faith-hearing, i.e., the act of receiving the message with trust) or (b) "the message that calls forth faith" (the faith-producing proclamation). Either reading makes the point: the Spirit arrived through the act of hearing and trusting the gospel, not through law-observance. Paul calls this a single argument sufficient to decide the case — the Galatians know how they received the Spirit, and law-keeping had nothing to do with it.</p>',
    "3": '<p><strong>ἐναρξάμενοι πνεύματι νῦν σαρκὶ ἐπιτελεῖσθε</strong> — "having begun by the Spirit, are you now being completed by the flesh?" <em>Enarchomai</em> (to begin, make a start) and <em>epiteleō</em> (to complete, bring to full realization, perfect) frame the question as one of completion: the Spirit inaugurated the Galatians\' Christian life; to seek law-keeping as its completion is to seek a fleshly fulfillment of what was spiritually begun. <em>Sarki</em> (by the flesh) here denotes human effort and achievement as the mode of completion, not moral evil — the problem is category, not character: seeking to perfect by human means what God began by grace.</p>',
    "4": '<p><strong>τοσαῦτα ἐπάθετε εἰκῇ</strong> (<em>epathete eikē</em>) — "did you experience so many things in vain?" <em>Paschō</em> can mean either "to experience" (neutral) or "to suffer" (specifically negative). Both senses probably operate here: the Galatians\' experiences include blessings (gifts of the Spirit, v5) and probable social suffering (persecution from their own Jewish communities for embracing Paul\'s law-free gospel). To adopt circumcision and law-keeping now would retroactively declare all of it meaningless — they suffered for nothing if law-keeping was the essential thing they were missing.</p>',
    "5": '<p><strong>ὁ οὖν ἐπιχορηγῶν ὑμῖν τὸ πνεῦμα καὶ ἐνεργῶν δυνάμεις ἐν ὑμῖν</strong> (<em>epichorēgōn</em>) — "the one who supplies you the Spirit and works miracles among you." <em>Epichorēgeō</em> (to supply bountifully, provide at one\'s own expense) derives from the Athenian practice of the wealthy citizen (<em>chorēgos</em>) who funded the theatrical chorus; the image is of lavish patron-scale provision. God supplies the Spirit not grudgingly but with patron-like abundance. <em>Energōn dynameis</em> (working miracles, operating powerful acts) — the present participle describes ongoing miraculous activity in the Galatian communities at the time of writing.</p>',
    "6": '<p><strong>Ἀβραὰμ ἐπίστευσεν τῷ θεῷ καὶ ἐλογίσθη αὐτῷ εἰς δικαιοσύνην</strong> — citing Gen 15:6 (the same text as Rom 4:3). The aorist <em>episteusen</em> (believed) points to the specific act of trusting the divine promise of Gen 15:5 (offspring as numerous as the stars). The aorist passive <em>elogisthē</em> (was credited, was reckoned) — God\'s forensic act in response: a reckoning of righteousness based on faith, not on circumcision (which came in Gen 17, after the faith-reckoning). Paul\'s argument in ch 3 deploys Gen 15:6 as the foundational proof that the Abrahamic principle was always faith, since the law came 430 years after Abraham (v17).</p>',
    "7": '<p><strong>οἱ ἐκ πίστεως, οὗτοί εἰσιν υἱοὶ Ἀβραάμ</strong> — "those who are of faith are the sons of Abraham." <em>Hoi ek pisteōs</em> (the faith-people, those who derive their standing from faith) is Paul\'s compact counter-definition of Abraham\'s true heirs: not those from ethnic descent or circumcision-lineage but those from the same faith-principle by which Abraham himself was reckoned righteous. The hermeneutical move redefines the people of God without denying the Abrahamic covenant — it claims the covenant\'s deepest logic against those who read it as an ethnic entailment.</p>',
    "8": '<p><strong>προϊδοῦσα δὲ ἡ γραφὴ... προευηγγελίσατο τῷ Ἀβραάμ</strong> (<em>proeuangelizomai</em>) — "Scripture, foreseeing... proclaimed the gospel in advance to Abraham." <em>Proeuangelizomai</em> (to pre-proclaim the gospel, announce the good news beforehand) — a verb Paul appears to have coined (or uses uniquely in this form); the gospel is not a NT invention but the fulfillment of a pre-proclamation already embedded in the Genesis text. The personification <em>proiidousa hē graphē</em> (Scripture foreseeing) presents the OT text as a divinely-sighted agent: Gen 12:3 ("all nations will be blessed through you") was foresight of the Gentile mission, not merely ethnic promise.</p>',
    "9": '<p><strong>ὥστε οἱ ἐκ πίστεως εὐλογοῦνται σὺν τῷ πιστῷ Ἀβραάμ</strong> — "so then, those who rely on faith are blessed along with Abraham, the man of faith." <em>Syn</em> (together with, alongside) — the Gentile faith-people enter the Abrahamic blessing-stream not as separate recipients of a different promise but as sharers in the same blessing in which Abraham stands. <em>Pistos Abraam</em> (believing / faithful Abraham) — the epithet identifies Abraham by his defining characteristic: his trust. The Gentile believers share both the mechanism (faith) and the destination (blessing) with their Abrahamic prototype.</p>',
    "10": '<p><strong>ἐπικατάρατος πᾶς ὃς οὐκ ἐμμένει πᾶσιν τοῖς γεγραμμένοις ἐν τῷ βιβλίῳ τοῦ νόμου</strong> — citing Deut 27:26. The curse requires doing <em>everything</em> (<em>pasin</em>) written in the law — partial compliance is still non-compliance. <em>Emmenō</em> (to remain in, continue in, abide by) targets the sustained, ongoing character of what the law demands: not a single act of obedience but uninterrupted, total compliance. The curse is therefore comprehensive: anyone who enters the law\'s framework takes on an obligation no human being has ever met, and falls under the curse the moment the perfect compliance breaks down.</p>',
    "11": '<p><strong>ὅτι δὲ ἐν νόμῳ οὐδεὶς δικαιοῦται παρὰ τῷ θεῷ δῆλον</strong> — "that no one is justified before God by the law is clear." <em>Dēlon</em> (clear, evident, self-evident) — Paul treats this as derivable from Scripture itself, not merely from his argument. The proof is Hab 2:4: "the righteous will live by faith" — if faith is the principle of the righteous person\'s life, law-performance cannot be that principle. The two texts (Deut 27:26 and Hab 2:4) bracket the discussion: the law brings curse; the prophets establish faith as the source of life.</p>',
    "12": '<p><strong>ὁ δὲ νόμος οὐκ ἔστιν ἐκ πίστεως</strong> — "but the law is not from faith." The law and faith operate by different and logically exclusive principles: the law demands doing (<em>poiēsas auta zēsetai</em> = "the one who does them will live," citing Lev 18:5); faith receives as gift what it cannot produce. The two systems cannot simultaneously function as the mechanism of justification — one cannot both receive righteousness as a gift and earn it as a wage (cf. Rom 4:4-5). The law is not wrong but it is categorically different from faith.</p>',
    "13": '<p><strong>Χριστὸς ἡμᾶς ἐξηγόρασεν ἐκ τῆς κατάρας τοῦ νόμου γενόμενος ὑπὲρ ἡμῶν κατάρα</strong> — "Christ redeemed us from the curse of the law by becoming a curse for us." <em>Exagorazō</em> (to buy out of, ransom from the slave market) — the redemption image: the law\'s curse had a price, and Christ paid it by bearing it himself. The opening of this verse has no connecting particle in Greek, giving it a staccato sharpness — a deliberate stylistic move that makes the statement land without diplomatic preparation. <em>Genomenos hyper hēmōn katara</em> (having become a curse on our behalf) — Paul says Christ actually became the curse itself, not merely that he suffered its effects: the one who bore it became what it was. The citation of Deut 21:23 (<em>epikataratos pas ho kremamenos epi xylou</em> = cursed is everyone who hangs on a tree) connects Roman crucifixion to the Deuteronomic curse-structure: the cross was not merely a method of execution but the form of the covenant curse.</p>',
    "14": '<p><strong>ἵνα εἰς τὰ ἔθνη ἡ εὐλογία τοῦ Ἀβραὰμ γένηται ἐν Χριστῷ Ἰησοῦ</strong> — "so that the blessing of Abraham might come to the Gentiles through Christ Jesus." The double <em>hina</em> (purpose clauses) reveals that Christ\'s curse-bearing has two goals: (1) the Abrahamic blessing reaches the Gentiles, and (2) the promised Spirit is received through faith. The Spirit is identified as the content of the Abrahamic blessing in its new-covenant form: what the promise to Abraham ultimately delivers is not merely territory or national descendants but the Spirit who creates the new-covenant family across all nations.</p>',
    "15": '<p><strong>κατὰ ἄνθρωπον λέγω</strong> — "I am speaking in human terms." The shift to an everyday legal analogy (<em>kata anthrōpon</em> = according to human practice) grounds the theological argument in accessible civil experience before the audience argues it has no relevance to divine dealings. <strong>ὅμως ἀνθρώπου κεκυρωμένην διαθήκην οὐδεὶς ἀθετεῖ ἢ ἐπιδιατάσσεται</strong> — "no one annuls or adds to a ratified human will/covenant." <em>Kekyrōmenēn diathēkēn</em> (ratified covenant, confirmed legal document) — the perfect participle indicates the permanent validity of the ratification; a sealed covenant cannot be unilaterally altered by one party under both Greek and Roman law. The <em>a fortiori</em> argument is unstated but obvious: if humans honor their ratified covenants, how much more must God\'s ratified promise stand inviolate.</p>',
    "16": '<p><strong>τῷ δὲ Ἀβραὰμ ἐρρέθησαν αἱ ἐπαγγελίαι καὶ τῷ σπέρματι αὐτοῦ</strong> — "the promises were spoken to Abraham and to his seed." <strong>οὐ λέγει· καὶ τοῖς σπέρμασιν... ἀλλ᾽ ὡς ἐφ᾽ ἑνός· καὶ τῷ σπέρματί σου, ὅς ἐστιν Χριστός</strong> — "it does not say \'seeds,\' referring to many, but \'your seed,\' referring to one, who is Christ." Paul\'s exegesis of the singular <em>sperma</em> (seed) in Genesis deploys a rabbinic method: noticing the grammatical number of a word and drawing theological inference from it. This was a recognized interpretive technique in Second Temple Judaism. The argument identifies the ultimate referent of the Abrahamic promise not as a collective ethnic lineage but as the singular Seed-who-is-Christ — making the promise fundamentally messianic, not merely genealogical.</p>',
    "17": '<p><strong>ὁ μετὰ τετρακόσια καὶ τριάκοντα ἔτη γεγονὼς νόμος οὐκ ἀκυροῖ</strong> — "the law, which came four hundred and thirty years later, does not annul the covenant." The 430 years from Exod 12:40 (the length of the Egyptian sojourn) establishes the chronological priority of the Abrahamic promise over the Sinaitic law: promise first, law second — and the later cannot retroactively invalidate the prior. <em>Akuroō</em> (to deprive of authority, invalidate, cancel) — the precise legal term for nullifying a prior legal instrument; the covenant-promise is not only prior but immune to retrospective annulment by any subsequent decree.</p>',
    "18": '<p><strong>εἰ γὰρ ἐκ νόμου ἡ κληρονομία, οὐκέτι ἐξ ἐπαγγελίας</strong> — "if the inheritance is from the law, it is no longer from the promise." The two principles — law and promise — are mutually exclusive as the basis of inheritance; if one operates, the other cannot. <strong>τῷ δὲ Ἀβραὰμ δι᾽ ἐπαγγελίας κεκχάρισται ὁ θεός</strong> — "God graciously gave it to Abraham through a promise." <em>Kecharistamai</em> (perfect of <em>charizomai</em>) — the gift was given as an act of grace and the giving stands permanently: the perfect tense marks the irrevocability. Inheritance-by-law and inheritance-by-gift are not two versions of the same thing; they are structurally opposed mechanisms.</p>',
    "19": '<p><strong>ὁ νόμος τῶν παραβάσεων χάριν προσετέθη</strong> — "the law was added because of transgressions." <em>Prostithēmi</em> (to add alongside, add in addition to something already existing) positions the law as supplementary, not foundational: it was added to the already-existing covenant-promise structure. <em>Tōn parabaseōn charin</em> (for the sake of transgressions) — the law\'s function in relation to sin is to define it as transgression, multiply it, and make it fully visible (cf. Rom 5:20; 7:7-8). <strong>ἄχρις οὗ ἔλθῃ τὸ σπέρμα</strong> — "until the Seed came" — the law had an explicitly temporary function, bounded by the arrival of Christ the Seed. <strong>διαταγεὶς δι᾽ ἀγγέλων ἐν χειρὶ μεσίτου</strong> — "ordained through angels by a mediator" — a Second Temple tradition (Deut 33:2 LXX; Acts 7:53; Heb 2:2) that the law was delivered at Sinai through the mediation of angels and Moses; the mediated, two-party character of the law contrasts with the directness of the divine promise given by God alone.</p>',
    "20": '<p><strong>ὁ δὲ μεσίτης ἑνὸς οὐκ ἔστιν, ὁ δὲ θεὸς εἷς ἐστιν</strong> — "a mediator is not for one party alone, but God is one." The argument: mediation requires multiple parties (at minimum two) who must both perform their obligations. The promise, by contrast, was a unilateral divine declaration: God alone was the speaking party; no human response or compliance was required to make the promise valid. The law needed Moses as mediator and required Israel\'s obedience as the condition; the promise needed neither. Its validity rests entirely on God\'s own faithfulness, and God is one — undivided, unchanging, requiring no second party to ratify what he has declared.</p>',
    "21": '<p><strong>ὁ οὖν νόμος κατὰ τῶν ἐπαγγελιῶν τοῦ θεοῦ; μὴ γένοιτο</strong> — "is the law then opposed to the promises of God? By no means!" The anticipated objection: if the law is temporary, supplementary, and unable to justify, does this make it God\'s enemy? Paul\'s answer is no — but the reason reveals the law\'s real scope: <strong>εἰ γὰρ ἐδόθη νόμος ὁ δυνάμενος ζωοποιῆσαι, ὄντως ἐκ νόμου ἂν ἦν ἡ δικαιοσύνη</strong> — "for if a law had been given that was capable of giving life, righteousness would certainly have come from the law." The contrary-to-fact conditional is decisive: no such life-giving law was given. Law and promise operate in different domains — the law defines sin and cannot produce life; the promise gives what the law requires and cannot supply.</p>',
    "22": '<p><strong>ἀλλὰ συνέκλεισεν ἡ γραφὴ τὰ πάντα ὑπὸ ἁμαρτίαν</strong> (<em>synekleis en</em>) — "but Scripture locked up everything under sin." <em>Synkleiō</em> (to close in from all sides, hem in completely, shut up in an enclosure) — the image is of a shepherd closing his flock in a fold with no exit, or a net drawn tight around fish: the confinement is complete and there is no way out through one\'s own effort. Everything (<em>ta panta</em>) is enclosed — no exception for the especially devout. <strong>ἵνα ἡ ἐπαγγελία ἐκ πίστεως Ἰησοῦ Χριστοῦ δοθῇ τοῖς πιστεύουσιν</strong> — the purpose of the confinement is redemptive: the enclosure drives all toward the single available exit — the promise-gift given through faith in Christ.</p>',
    "23": '<p><strong>πρὸ τοῦ δὲ ἐλθεῖν τὴν πίστιν ὑπὸ νόμον ἐφρουρούμεθα συγκεκλεισμένοι</strong> — "before this faith came, we were held in custody under the law, locked in." <em>Phrouroumetha</em> (imperfect passive: we were being kept under guard) — the military image of garrison troops keeping a population in custody; the law\'s role was that of a jailer maintaining a state of confinement. <em>Sygkekleismenoi</em> (locked in together, doubly enclosed) — the compound intensifies the image of total confinement. Crucially, the custody was not punitive for its own sake but prospective: <em>eis tēn mellousan pistin apokalyphthēnai</em> — "in anticipation of the faith that was about to be revealed." The lock-up was a holding pattern, not a permanent sentence.</p>',
    "24": '<p><strong>ὥστε ὁ νόμος παιδαγωγὸς ἡμῶν γέγονεν εἰς Χριστόν</strong> — "so then the law was our guardian until Christ." <em>Paidagōgos</em> is not the teacher but the household slave who escorted a minor child to school, maintained discipline en route, and ensured the child arrived safely. The paidagōgos\' function was temporary by definition — it ended when the child reached majority. Paul\'s metaphor is precise: the law\'s role was custodial and preparatory, not pedagogical in the permanent or instructive sense. Its task was to escort Israel to Christ, the destination; once arrived, the escort\'s function is complete. <strong>ἵνα ἐκ πίστεως δικαιωθῶμεν</strong> — "so that we might be justified by faith" — the purpose of the preparatory guardianship: leading to the justification-by-faith that the Christ-event makes possible and available.</p>',
    "25": '<p><strong>ἐλθούσης δὲ τῆς πίστεως οὐκέτι ὑπὸ παιδαγωγόν ἐσμεν</strong> — "but now that this faith has come, we are no longer under a guardian." The aorist participle <em>elthousēs</em> (having come) marks the arrival of "faith" as a dateable historical event — the coming of Christ and the proclamation of his gospel. "No longer under a guardian" is the declaration of covenant maturity: the law\'s custodial role has ended for all who are in Christ. The Galatians who seek to take on the law\'s observances are going backward — seeking to return to minority status after the arrival of majority, to return to the escort-slave\'s hand after reaching the school.</p>',
    "26": '<p><strong>πάντες γὰρ υἱοὶ θεοῦ ἐστε διὰ τῆς πίστεως ἐν Χριστῷ Ἰησοῦ</strong> — "for you are all sons of God through faith in Christ Jesus." <em>Pantes</em> (all) — the universal scope is the point: all believers, without ethnic or social qualification, are sons/children of God. The status of covenant sonship that was previously the privilege of Israel-as-nation (Exod 4:22; Deut 14:1) is now available to all through union with the Son. <em>Dia tēs pisteōs en Christō</em> (through faith, in Christ) — the mechanism (faith) and the sphere (in Christ) are inseparable: sonship is not simply a new status assigned from outside but a relation entered by union with the one who is Son.</p>',
    "27": '<p><strong>ὅσοι γὰρ εἰς Χριστὸν ἐβαπτίσθητε, Χριστὸν ἐνεδύσασθε</strong> — "for all of you who were baptized into Christ have clothed yourselves with Christ." <em>Eis Christon ebaptisthēte</em> (were baptized into Christ) — the preposition <em>eis</em> (into) marks entry into a sphere, a relation, a new domain; baptism is the rite of incorporation, not merely a rite of initiation. <em>Enedysasthe</em> (aorist middle: you clothed yourselves, you put on) — the baptismal clothing image: the physical act of removing garments before the water and being vested in white afterward enacted the theological reality of putting on Christ as a new identity-garment. The putting-on is not external costume but a change in whose life defines your life.</p>',
    "28": '<p><strong>οὐκ ἔνι Ἰουδαῖος οὐδὲ Ἕλλην, οὐκ ἔνι δοῦλος οὐδὲ ἐλεύθερος, οὐκ ἔνι ἄρσεν καὶ θῆλυ</strong> — "there is neither Jew nor Greek, neither slave nor free, nor is there male and female." The three pairs cover the primary structural divisions of the ancient world: ethnic (Jew/Greek), socio-economic (slave/free), and biological (male/female). Note that the third pair shifts from <em>oude... oude</em> (neither... nor) to <em>kai</em> (and) — <em>arsen kai thēly</em> — possibly echoing the creation formula of Gen 1:27 ("male and female he created them"), suggesting that in Christ even the fundamental creaturely distinction is relativized in terms of standing before God.</p><p><em>Ouk eni</em> (there is not, it does not exist) — an emphatic contracted form: these categories do not function as determinants of standing in Christ. They are not abolished as real distinctions; they do not determine one\'s access to God or one\'s spiritual status within the community.</p>',
    "29": '<p><strong>εἰ δὲ ὑμεῖς Χριστοῦ, ἄρα τοῦ Ἀβραὰμ σπέρμα ἐστέ, κατ᾽ ἐπαγγελίαν κληρονόμοι</strong> — "if you belong to Christ, then you are Abraham\'s seed, and heirs according to the promise." The syllogism completing the argument of ch 3: Christ is the Seed of Abraham (v16); those who belong to Christ share his identity; therefore they are Abraham\'s seed and heirs. The inheritance is <em>kat\' epangelian</em> (according to promise) — not according to ethnic descent, not according to circumcision-status, not according to law-observance, but according to the original mechanism by which Abraham himself was reckoned righteous. The Gentile Galatians who are in Christ are Abraham\'s heirs in the fullest sense, because they stand on the same faith-ground on which Abraham stood before any of the national markers existed.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'galatians')
    # Restart: clear chs 1–3 so that new entries replace the prior version.
    for ch in ('1', '2', '3'):
        existing.pop(ch, None)
    merge_comm(existing, GALATIANS)
    save_comm('mkt-original', 'galatians', existing)
    print('Galatians 1–3 mkt-original written (restart).')

if __name__ == '__main__':
    main()
